  ('aboriginal-57f41407-moex-00562', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '依憲法規定與司法院大法官解釋，關於居住遷徙自由，下列敘述何者錯誤？', '["居住自由包含設定住、居所之自由", "遷徙自由包含遷徙、旅行、出境或入境之權利", "居住遷徙自由之限制，僅得以立法院制定法律之方式限制之", "人民入境居住之權利，得視規範對象有無臺灣地區戶籍，而容許合理差異之規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00563', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '依司法院大法官解釋，法律明確性原則之目的，不包括下列何者？', '["使受規範者可能預見其行為之法律效果", "確保法律預先告知之功能", "促進公民對法律之理解與思辨", "保障規範目的之實現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00564', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '關於依法行政原則之敘述，下列何者錯誤？', '["指行政之合法性原則，可分為法律優位原則與法律保留原則", "法規命令不得牴觸法律，為法律優位原則之內涵", "行政機關所為之私法行為不適用法律優位原則", "違反法律優位原則之法律效果，依行政行為的類型而有不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00565', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '對於甲公司所申報之營利事業所得稅，稅捐稽徵機關僅核定增列其營業收入金額，但未斟酌增列金額 所生之成本及費用，可能違反下列何者？', '["比例原則", "誠實信用原則", "信賴保護原則", "有利不利一律注意原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00566', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '有關行政法上誠實信用原則之敘述，下列何者錯誤？', '["誠實信用原則普遍為各法領域所共通適用", "僅對行政機關有其適用", "誠實信用原則有避免權利濫用之意涵", "行政行為違反誠實信用原則者，構成違法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00567', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '行政罰法有關共同實施違規行為之處罰，下列敘述何者正確？', '["行政罰法並無與刑法共犯相類似之共同實施規定", "只有故意才有共同實施行為", "共同實施違規行為者，應連帶處罰", "不論情節輕重，共同處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00568', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '依公務人員考績法規定，下列何者得對公務人員為記過之處分？', '["懲戒法庭", "行政法院", "公務人員之服務機關", "監察院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
